type unmarshableMapKey struct {
	Key string
}

func (mk *unmarshableMapKey) UnmarshalYAML(b []byte) error {
	mk.Key = string(b)
	return nil
}

func TestMapKeyCustomUnmarshaler(t *testing.T) {
	var m map[unmarshableMapKey]string
	if err := yaml.Unmarshal([]byte(`key: value`), &m); err != nil {
		t.Fatalf("failed to unmarshal %v", err)
	}
	if len(m) != 1 {
		t.Fatalf("expected 1 element in map, but got %d", len(m))
	}
	val, ok := m[unmarshableMapKey{Key: "key"}]
	if !ok {
		t.Fatal("expected to have element 'key' in map")
	}
	if val != "value" {
		t.Fatalf("expected to have value \"value\", but got %q", val)
	}
}

type NestedStruct struct {
	Key string `yaml:"key"`
}

type TestStruct struct {
	First    string       `yaml:"first"`
	Defaults NestedStruct `yaml:"second"`
}

func TestPreserveDefaultValuesWithNullNestedStruct(t *testing.T) {
	yml := `first: "Test"
second:
  # Just want to document the fields of the nested struct
#  key: "Value from YAML"
`

	test := TestStruct{Defaults: NestedStruct{Key: "My default Value"}}
	d := yaml.NewDecoder(strings.NewReader(yml))
	err := d.Decode(&test)
	if err != nil {
		t.Fatalf("failed to decode: %v", err)
	}

	if test.Defaults.Key != "My default Value" {
		t.Errorf("expected default value 'My default Value', got '%s'", test.Defaults.Key)
	}
}

