			if dereferencedVal.IsNil() {
				return reflect.Zero(typ), nil
			}
			dereferencedVal = dereferencedVal.Elem()
		}
		if dereferencedVal.IsValid() && dereferencedVal.Type().AssignableTo(typ) {
			return dereferencedVal, nil
		}
		return reflect.Zero(typ), nil
	}
